import { calcTotal, sortByCod } from './helpers'

// Logos em base64 para funcionarem offline na janela de impressão
const LOGO_LATTUGA = ''
const LOGO_KORIN   = ''

const printHeader = (nomeCliente, tel, periodo) => `
  <div style="display:flex;justify-content:space-between;align-items:center;padding-bottom:16px;border-bottom:3px solid #2D6A4F;margin-bottom:24px">
    <img src="data:image/png;base64,${LOGO_LATTUGA}" style="height:52px;width:auto" alt="Lattuga"/>
    <div style="text-align:center;flex:1;padding:0 12px">
      <div style="font-size:11px;color:#aaa;letter-spacing:2px;text-transform:uppercase;margin-bottom:4px">Ação Social Korin · ${periodo}</div>
      <div style="font-size:36px;font-weight:900;color:#2D6A4F;line-height:1">${nomeCliente}</div>
      ${tel ? `<div style="font-size:17px;color:#888;margin-top:4px">📱 ${tel}</div>` : ''}
    </div>
    <img src="data:image/png;base64,${LOGO_KORIN}" style="height:48px;width:auto" alt="Korin"/>
  </div>`

const printTotal = (total, pagamento) => `
  <div style="margin-top:26px;background:#2D6A4F;color:#fff;padding:20px 26px;border-radius:14px;display:flex;justify-content:space-between;align-items:center">
    <span style="font-size:22px;font-weight:700">TOTAL A PAGAR</span>
    <span style="font-size:34px;font-weight:900">R$ ${total}</span>
  </div>
  ${pagamento && pagamento !== 'A Definir'
    ? `<div style="text-align:center;margin-top:14px;font-size:17px;color:#555">Pagamento: <strong>${pagamento}</strong></div>`
    : ''}
  <div style="margin-top:32px;padding-top:14px;border-top:1px solid #eee;display:flex;justify-content:space-between;align-items:center">
    <span style="font-size:11px;color:#aaa">© Todos os Direitos Reservados — Lattuga Orgânicos</span>
    <a href="https://www.personalsupport.tec.br/" style="font-size:11px;color:#2D6A4F;text-decoration:underline">Desenvolvido por Personal Support</a>
  </div>`

const buildRows = (pedido, produtos) =>
  sortByCod(pedido.itens, produtos).map(it => {
    const p = produtos.find(x => x.id === it.produtoId)
    if (!p) return ''
    return `<tr>
      <td style="padding:13px 15px;border-bottom:2px solid #f0f0f0;font-size:20px;color:#888;width:55px;font-weight:700">${p.cod}</td>
      <td style="padding:13px 15px;border-bottom:2px solid #f0f0f0;font-size:21px">${it.qty}× ${p.nome}<br><span style="font-size:13px;color:#aaa">${p.unidade}</span></td>
      <td style="padding:13px 15px;border-bottom:2px solid #f0f0f0;font-size:21px;font-weight:900;text-align:right;color:#1a4a35">R$ ${(p.preco * it.qty).toFixed(2).replace('.', ',')}</td>
    </tr>`
  }).join('')

const wrapDoc = (title, body) => `<!DOCTYPE html><html><head>
  <meta charset="utf-8"><title>${title}</title>
  <style>body{font-family:Arial,sans-serif;margin:0;padding:32px}@media print{.noprint{display:none!important}}</style>
</head><body>${body}</body></html>`

export const printPedido = (pedido, produtos, periodo) => {
  const total = calcTotal(pedido, produtos).toFixed(2).replace('.', ',')
  const w = window.open('', '_blank')
  w.document.write(wrapDoc(`Pedido ${pedido.clienteNome}`, `
    ${printHeader(pedido.clienteNome, pedido.clienteTel, periodo)}
    <table style="width:100%;border-collapse:collapse">${buildRows(pedido, produtos)}</table>
    ${printTotal(total, pedido.pagamento)}
    <div class="noprint" style="text-align:center;margin-top:40px">
      <button onclick="window.print()" style="background:#2D6A4F;color:#fff;border:none;padding:14px 44px;border-radius:10px;font-size:20px;cursor:pointer;font-weight:700">🖨️ Imprimir</button>
    </div>`))
  w.document.close()
}

export const printTodos = (pedidos, produtos, periodo) => {
  const pendentes = pedidos
    .filter(p => p.status === 'pendente')
    .sort((a, b) => a.clienteNome.localeCompare(b.clienteNome))

  const blocos = pendentes.map(pedido => {
    const total = calcTotal(pedido, produtos).toFixed(2).replace('.', ',')
    const rows  = sortByCod(pedido.itens, produtos).map(it => {
      const p = produtos.find(x => x.id === it.produtoId)
      if (!p) return ''
      return `<tr>
        <td style="padding:11px 13px;border-bottom:1px solid #eee;font-size:18px;color:#888;width:48px;font-weight:700">${p.cod}</td>
        <td style="padding:11px 13px;border-bottom:1px solid #eee;font-size:20px">${it.qty}× ${p.nome}<br><span style="font-size:12px;color:#aaa">${p.unidade}</span></td>
        <td style="padding:11px 13px;border-bottom:1px solid #eee;font-size:20px;font-weight:700;text-align:right;color:#1a4a35">R$ ${(p.preco * it.qty).toFixed(2).replace('.', ',')}</td>
      </tr>`
    }).join('')
    return `<div style="page-break-after:always;padding:28px">
      ${printHeader(pedido.clienteNome, pedido.clienteTel, periodo)}
      <table style="width:100%;border-collapse:collapse">${rows}</table>
      ${printTotal(total, pedido.pagamento)}
    </div>`
  }).join('')

  const w = window.open('', '_blank')
  w.document.write(wrapDoc(`Pedidos ${periodo}`, `
    <div class="noprint" style="text-align:center;padding:18px;background:#f5f5f5">
      <button onclick="window.print()" style="background:#2D6A4F;color:#fff;border:none;padding:12px 36px;border-radius:8px;font-size:18px;cursor:pointer;font-weight:700">🖨️ Imprimir Todos (${pendentes.length} pedidos)</button>
      <p style="color:#999;font-size:13px;margin-top:6px">Cada pedido em uma folha A4</p>
    </div>
    ${blocos}`))
  w.document.close()
}
